const rows = $input.all();

const body = $('Webhook').first().json.body ?? $('Webhook').first().json;

const toolCallId =
  body.toolCallId ||
  body.message?.toolCallId ||
  body.message?.toolCallList?.[0]?.id ||
  body.message?.toolWithToolCallList?.[0]?.toolCall?.id ||
  "";

if (!rows.length || !rows[0]?.json || Object.keys(rows[0].json).length === 0) {
  return [
    {
      json: {
        results: [
          {
            toolCallId: String(toolCallId),
            result: "Our menu is currently unavailable."
          }
        ]
      }
    }
  ];
}

const menuText = rows
  .map((row) => {
    const item =
      row.json.Item ||
      row.json.Name ||
      row.json.Dish ||
      row.json.Meal ||
      "Menu item";

    const price = row.json.Price ? ` - ${row.json.Price}` : "";
    return `${item}${price}`;
  })
  .join(", ");

return [
  {
    json: {
      results: [
        {
          toolCallId: String(toolCallId),
          result: `Today's menu includes: ${menuText}.`
        }
      ]
    }
  }
];
